# scripts/select_affected_evals.py
"""Identify eval cases affected by changed files."""
import subprocess, json, pathlib

EVAL_MANIFEST = pathlib.Path("evals/manifest.json")

def changed_files() -> set[str]:
    output = subprocess.check_output(
        ["git", "diff", "--name-only", "origin/main...HEAD"], text=True
    )
    return set(output.splitlines())

def load_manifest() -> dict:
    """
    manifest.json maps source files to the eval IDs that test them.
    {
      "src/prompts/system.txt": ["eval-001", "eval-005", "eval-012"],
      "src/tools/web_search.json": ["eval-007", "eval-011"]
    }
    """
    return json.loads(EVAL_MANIFEST.read_text())

def affected_eval_ids() -> list[str]:
    manifest = load_manifest()
    changed = changed_files()
    ids: set[str] = set()
    for file, eval_ids in manifest.items():
        if file in changed:
            ids.update(eval_ids)
    # If core infrastructure changed, run everything
    if any(f.startswith("src/llm_client") for f in changed):
        return []  # empty = run all
    return sorted(ids)

if __name__ == "__main__":
    ids = affected_eval_ids()
    if not ids:
        print("RUN_ALL")
    else:
        print(",".join(ids))

# scripts/check_baseline_drift.py
import json, pathlib, sys

HISTORY_FILE = pathlib.Path("eval_baselines/history.json")
DRIFT_ALERT_THRESHOLD = 0.05  # alert if pass rate dropped >5pp vs 30-day average

def load_history() -> list[dict]:
    if not HISTORY_FILE.exists():
        return []
    return json.loads(HISTORY_FILE.read_text())

def check_drift(current_pass_rate: float) -> None:
    history = load_history()
    if len(history) < 5:
        print("Insufficient history for drift detection — skipping")
        return

    # Use the last 30 entries as the rolling baseline
    recent = history[-30:]
    rolling_avg = sum(h["pass_rate"] for h in recent) / len(recent)

    drift = rolling_avg - current_pass_rate
    if drift > DRIFT_ALERT_THRESHOLD:
        print(f"DRIFT ALERT: current {current_pass_rate:.2%} is {drift:.2%} below 30-day avg {rolling_avg:.2%}")
        sys.exit(1)
    else:
        print(f"No drift: current {current_pass_rate:.2%}, 30-day avg {rolling_avg:.2%}, delta {drift:+.2%}")

def append_history(pass_rate: float, sha: str) -> None:
    history = load_history()
    history.append({"sha": sha[:8], "pass_rate": pass_rate})
    HISTORY_FILE.write_text(json.dumps(history[-90:], indent=2))  # keep 90 entries
